import { Autumn } from 'autumn-js';
import { writeFile } from 'fs/promises';
import crypto from 'crypto';

// Generate idempotency key - use environment variable if set, otherwise generate UUID
const idempotencyKey = process.env.IDEMPOTENCY_KEY || crypto.randomUUID();

console.log(`Idempotency Key: ${idempotencyKey}`);

// Initialize Autumn client with secret key from environment
const autumn = new Autumn({
  secretKey: process.env.AUTUMN_SECRET_KEY
});

// Track usage event with idempotency key
async function trackUsage() {
  try {
    const result = await autumn.track(
      {
        customerId: "user_test_001",
        featureId: "api-calls",
        value: 1
      },
      {
        headers: {
          "Idempotency-Key": idempotencyKey
        }
      }
    );

    console.log('Usage tracked successfully:', result);

    // Save result to JSON file
    await writeFile(
      '/home/user/myproject/track_result.json',
      JSON.stringify(result, null, 2),
      'utf-8'
    );

    console.log('Result saved to track_result.json');
    return result;
  } catch (error) {
    console.error('Error tracking usage:', error);
    throw error;
  }
}

// Run the function
trackUsage().catch(console.error);

